			'pacific/wallis'                 => 'Wallis and Futuna',
		];

	/**
	 *
	 * Returns country name based on time zone name.
	 *
	 * @param   string  $zoneName
	 *
	 * @return string
	 */
	public static function countryFromZone($zoneName)
	{
		return Wb\arrayGet(
			self::ZONES_DATA,
			strtolower($zoneName),
			''
		);
	}
}
